INSERT INTO `t_product` (`id`, `shop_id`, `category_id`, `brand_id`, `name`, `subtitle`, `description`, `main_image`, `price`, `original_price`, `stock`, `sales`, `view_count`, `favorite_count`, `review_count`, `avg_review_score`, `is_recommended`, `is_new`, `publish_time`, `status`, `created_at`, `updated_at`, `created_by`, `updated_by`, `deleted`) VALUES (1,1,12,2,'iPhone 15 Pro','钛金属设计，A17 Pro芯片，4800万像素主摄','<p>Apple iPhone 15 Pro 采用钛金属设计，搭载 A17 Pro 芯片，配备 4800 万像素主摄像头。支持 USB-C 接口，动作按钮可自定义功能。</p>','/uploads/products/cat12_prod121.webp',7999.00,8999.00,50,0,0,0,0,5.0,1,0,'2026-07-07 00:00:00','PUBLISHED','2026-07-15 23:20:51','2026-07-15 23:23:21',1,1,0),(2,1,12,5,'华为 Mate 60 Pro','麒麟9000S芯片，卫星通话，超可靠玄武架构','<p>华为 Mate 60 Pro 搭载麒麟 9000S 芯片，支持卫星通话功能。超可靠玄武架构，第二代昆仑玻璃，十档可变光圈。</p>','/uploads/products/cat12_prod122.webp',6999.00,7999.00,80,0,0,0,0,5.0,1,0,'2026-07-07 00:00:00','PUBLISHED','2026-07-15 23:20:51','2026-07-15 23:23:21',1,1,0),(3,1,12,1,'小米14 Ultra','徕卡光学全焦段四摄，骁龙8 Gen3，卫星通信','<p>小米14 Ultra 配备徕卡光学全焦段四摄，搭载第三代骁龙8移动平台。支持双向卫星通信，5300mAh大电池。</p>','/uploads/products/cat12_prod123.webp',6499.00,6999.00,100,0,0,0,0,5.0,1,1,'2026-07-07 00:00:00','PUBLISHED','2026-07-15 23:20:51','2026-07-15 23:23:21',1,1,0),(4,1,12,5,'OPPO Find X7 Ultra','双潜望四主摄，哈苏影像，潮汐架构','<p>OPPO Find X7 Ultra 搭载双潜望四主摄系统，哈苏联合研发影像。潮汐架构提升能效，100W超级闪充。</p>','/uploads/products/cat12_prod124.webp',5999.00,6999.00,60,0,0,0,0,5.0,1,0,'2026-07-07 00:00:00','PUBLISHED','2026-07-15 23:20:51','2026-07-15 23:23:21',1,1,0),(5,1,12,2,'vivo X100 Pro','蔡司APO超级长焦，天玑9300，蓝海电池','<p>vivo X100 Pro 配备蔡司 APO 超级长焦镜头，搭载天玑 9300 旗舰芯片。蓝海电池技术，120W双芯闪充。</p>','/uploads/products/cat12_prod125.webp',4999.00,5499.00,90,0,0,0,0,5.0,1,0,'2026-07-07 00:00:00','PUBLISHED','2026-07-15 23:20:51','2026-07-15 23:23:21',1,1,0),(6,1,13,5,'MacBook Air M3','轻薄便携，M3芯片强劲性能，18小时续航','<p>全新 MacBook Air 搭载 M3 芯片，轻薄设计，支持双屏显示。18小时电池续航，1080p FaceTime 高清摄像头。</p>','/uploads/products/cat13_prod126.webp',8999.00,9999.00,30,0,0,0,0,5.0,1,1,'2026-07-07 00:00:00','PUBLISHED','2026-07-15 23:20:51','2026-07-15 23:23:21',1,1,0),(7,1,13,5,'华为MateBook X Pro','微绒金属机身，3.1K原色屏，智慧办公','<p>华为 MateBook X Pro 采用微绒金属机身，配备 3.1K 原色全面屏。支持超级终端，智慧办公体验升级。</p>','/uploads/products/cat13_prod147.jpg',9999.00,11999.00,25,0,0,0,0,5.0,1,0,'2026-07-07 00:00:00','PUBLISHED','2026-07-15 23:20:51','2026-07-15 23:23:21',1,1,0),(8,1,13,2,'联想小新Pro 16','13代酷睿i7，2.5K高刷屏，大电池长续航','<p>联想小新 Pro 16 搭载第13代英特尔酷睿 i7 处理器，2.5K 120Hz 高刷屏。75Wh 大电池，支持快充。</p>','/uploads/products/cat13_prod148.jpg',5499.00,6499.00,50,0,0,0,0,5.0,1,0,'2026-07-07 00:00:00','PUBLISHED','2026-07-15 23:20:51','2026-07-15 23:23:21',1,1,0),(9,1,13,2,'戴尔XPS 15','4K OLED触控屏，RTX 4060，创作者首选','<p>戴尔 XPS 15 配备 4K OLED 触控显示屏，可选 RTX 4060 显卡。CNC 精雕机身，创作者移动工作站首选。</p>','/uploads/products/cat13_prod149.jpg',14999.00,16999.00,15,0,0,0,0,5.0,1,1,'2026-07-07 00:00:00','PUBLISHED','2026-07-15 23:20:51','2026-07-15 23:23:21',1,1,0),(10,1,13,2,'华硕天选5 Pro','锐龙9处理器，RTX 4070，2.5K电竞屏','<p>华硕天选5 Pro 搭载 AMD 锐龙 9 处理器，配备 RTX 4070 显卡。2.5K 165Hz 电竞屏，冰川散热架构。</p>','/uploads/products/cat13_prod150.jpg',8999.00,10499.00,40,0,0,0,0,5.0,1,0,'2026-07-07 00:00:00','PUBLISHED','2026-07-15 23:20:51','2026-07-15 23:23:21',1,1,0),(11,1,14,5,'AirPods Pro 2','主动降噪，通透模式，空间音频','<p>AirPods Pro 第二代配备 H2 芯片，主动降噪效果最高提升至 2 倍。支持自适应通透模式，单次充电聆听时间最长可达 6 小时。</p>','/uploads/products/cat14_prod157.jpg',1899.00,2299.00,100,0,0,0,0,5.0,1,0,'2026-07-07 00:00:00','PUBLISHED','2026-07-15 23:20:51','2026-07-15 23:23:21',1,1,0),(12,1,14,2,'索尼WH-1000XM5','行业领先降噪，30小时续航，舒适佩戴','<p>索尼 WH-1000XM5 头戴式降噪耳机，配备两个处理器控制 8 个麦克风。30 小时超长续航，轻量化设计佩戴舒适。</p>','/uploads/products/cat14_prod158.jpg',2499.00,2999.00,60,0,0,0,0,5.0,1,1,'2026-07-07 00:00:00','PUBLISHED','2026-07-15 23:20:51','2026-07-15 23:23:21',1,1,0),(13,1,14,1,'华为FreeBuds Pro 3','星闪连接，智慧动态降噪，无损音质','<p>华为 FreeBuds Pro 3 支持星闪连接技术，智慧动态降噪 3.0。超感知原声双单元，支持 L2HC 无损音质传输。</p>','/uploads/products/cat14_prod33.jpg',1499.00,1699.00,80,0,0,0,0,5.0,1,0,'2026-07-07 00:00:00','PUBLISHED','2026-07-15 23:20:51','2026-07-15 23:23:21',1,1,0),(14,1,14,5,'JBL Pulse 5','360度全彩灯光秀，40W大功率，IP67防水','<p>JBL Pulse 5 音乐脉动五代，360度全彩灯光秀随音乐律动。40W 大功率输出，IP67 防尘防水，12小时续航。</p>','/uploads/products/cat14_prod34.jpg',1899.00,2199.00,45,0,0,0,0,5.0,1,0,'2026-07-07 00:00:00','PUBLISHED','2026-07-15 23:20:51','2026-07-15 23:23:21',1,1,0),(15,1,14,2,'小米Sound Pro','哈曼调音，7单元声学，NFC一碰传音','<p>小米 Sound Pro 高保真智能音箱，经哈曼卡顿专业调音。7单元声学架构，360度全向出音，支持 NFC 一碰传音。</p>','/uploads/products/cat14_prod35.jpg',999.00,1299.00,70,0,0,0,0,5.0,1,1,'2026-07-07 00:00:00','PUBLISHED','2026-07-15 23:20:51','2026-07-15 23:23:21',1,1,0),(16,2,15,6,'雅诗兰黛小棕瓶精华','第七代特润修护肌活精华露，抗老修护','<p>雅诗兰黛第七代小棕瓶精华，加速肌因修护，激活细胞新生。早晚使用，肌肤更紧致、更弹润、更透亮。</p>','/uploads/products/cat15_prod42.jpg',850.00,1080.00,200,0,0,0,0,5.0,1,0,'2026-07-07 00:00:00','PUBLISHED','2026-07-15 23:20:51','2026-07-15 23:23:21',1,1,0),(17,2,15,4,'SK-II神仙水','PITERA精华，改善肤质，晶莹剔透','<p>SK-II 护肤精华露（神仙水），蕴含超过 90% PITERA 成分。帮助改善肤质，令肌肤晶莹剔透，焕发自然光彩。</p>','/uploads/products/cat15_prod43.jpg',1540.00,1890.00,100,0,0,0,0,5.0,0,0,'2026-07-07 00:00:00','PUBLISHED','2026-07-15 23:20:51','2026-07-15 23:23:21',1,1,0),(18,2,15,4,'兰蔻小黑瓶肌底液','强维稳快修护，肌肤细腻透亮','<p>兰蔻第二代小黑瓶肌底精华液， Bio-7 生物专研配方。强维稳快修护，7天肌肤细腻透亮，改善粗糙泛红。</p>','/uploads/products/cat15_prod44.jpg',1080.00,1280.00,150,0,0,0,0,5.0,0,1,'2026-07-07 00:00:00','PUBLISHED','2026-07-15 23:20:51','2026-07-15 23:23:21',1,1,0),(19,2,15,3,'海蓝之谜修护精萃水','神奇活性精萃，深层修护，焕活肌肤','<p>海蓝之谜修护精萃水，蕴含神奇活性精萃 Mirackle Broth。深层修护焕活肌肤，质地如丝缎般柔滑。</p>','/uploads/products/cat15_prod121.webp',1290.00,1520.00,80,0,0,0,0,5.0,0,0,'2026-07-07 00:00:00','PUBLISHED','2026-07-15 23:20:51','2026-07-15 23:23:21',1,1,0),(20,2,15,6,'欧莱雅复颜玻尿酸水乳套装','玻尿酸补水，淡化细纹，紧致肌肤','<p>欧莱雅复颜玻尿酸系列水乳套装，蕴含高纯度玻尿酸。深层补水保湿，淡化细纹，提拉紧致肌肤轮廓。</p>','/uploads/products/cat15_prod122.webp',399.00,520.00,300,0,0,0,0,5.0,0,0,'2026-07-07 00:00:00','PUBLISHED','2026-07-15 23:20:51','2026-07-15 23:23:21',1,1,0),(21,2,16,4,'迪奥烈艳蓝金口红','999经典正红，丝绒质地，显白不拔干','<p>迪奥烈艳蓝金唇膏 999，经典正红色号。丝绒质地，显白不拔干，持久显色，一抹尽显高级妆感。</p>','/uploads/products/cat16_prod125.webp',3